const call = $json.call;
const analysis = call.call_analysis ?? {};

// Determine outcome from analysis
let outcome = 'resolved';
if (analysis.in_voicemail) outcome = 'voicemail';
else if (analysis.call_successful === false) outcome = 'follow_up_required';
else {
  const summary = (analysis.call_summary ?? '').toLowerCase();
  if (summary.includes('book') || summary.includes('appointment confirmed')) outcome = 'booked';
  else if (summary.includes('escalat') || summary.includes('transfer')) outcome = 'escalated';
}

// Determine urgency
let urgency = 'low';
const summary = (analysis.call_summary ?? '').toLowerCase();
if (summary.includes('urgent') || summary.includes('emergency') || summary.includes('a&e')) urgency = 'urgent';
else if (summary.includes('pain') && summary.includes('severe')) urgency = 'high';
else if (summary.includes('follow up') || summary.includes('callback')) urgency = 'medium';

const durationMs = call.duration_ms ?? (
  call.end_timestamp && call.start_timestamp
    ? call.end_timestamp - call.start_timestamp
    : null
);

return [{
  callId: call.call_id,
  agentId: call.agent_id,
  callType: call.call_type ?? 'phone_call',
  callStatus: 'analyzed',
  callerPhone: call.from_number ?? null,
  toNumber: call.to_number ?? null,
  patientId: call.metadata?.patientId ?? null,
  reasonForCall: call.metadata?.reasonForCall ?? null,
  outcome,
  urgency,
  callSummary: analysis.call_summary ?? null,
  userSentiment: analysis.user_sentiment ?? null,
  callSuccessful: analysis.call_successful ?? null,
  inVoicemail: analysis.in_voicemail ?? false,
  transcript: call.transcript ?? null,
  recordingUrl: call.recording_url ?? null,
  durationSeconds: durationMs != null ? Math.round(durationMs / 1000) : null,
  startTimestamp: call.start_timestamp ?? null,
  endTimestamp: call.end_timestamp ?? null,
  disconnectionReason: call.disconnection_reason ?? null,
  updatedAt: new Date().toISOString(),
}];
